import json, os, sys, re

root = "/root/.openclaw"
secrets_found = []

for dirpath, dirnames, filenames in os.walk(root):
    # skip node_modules and sessions
    if 'node_modules' in dirpath or 'sessions' in dirpath:
        continue
    for fn in filenames:
        if not fn.endswith('.json'):
            continue
        fp = os.path.join(dirpath, fn)
        try:
            with open(fp) as f:
                d = json.load(f)
        except:
            continue
        def scan(obj, path=""):
            if isinstance(obj, dict):
                for k, v in obj.items():
                    kl = k.lower().replace('_','').replace('-','')
                    if any(x in kl for x in ['apikey','token','secret','password']):
                        if isinstance(v, str) and len(v) > 4 and not v.startswith('${'):
                            secrets_found.append((fp, f"{path}.{k}", v[:12]+'...'+v[-4:], len(v)))
                    scan(v, f"{path}.{k}")
            elif isinstance(obj, list):
                for i, v in enumerate(obj):
                    scan(v, f"{path}[{i}]")
        scan(d)

for fpath, field, val, length in sorted(set(secrets_found)):
    print(f"{fpath}")
    print(f"  {field} = {val} (len={length})")
